class PaymentProcessor {
  static const String _apiKey = 'your_api_key_here';
  static const String _apiUrl = 'https://api.paymentgateway.com';
  static const String _merchantId = 'your_merchant_id';

  static Future<bool> purchaseProduct(String productId) async {
    try {
      final bool available = await InAppPurchase.instance.isAvailable();
      if (!available) return false;

      final List<PurchaseParam> purchaseParams = [
        PurchaseParam(
          productDetails: await _getProductDetails(productId),
          applicationUserName: 'user_123',
        )
      ];

      final StreamSubscription<List<PurchaseDetails>> subscription =
          InAppPurchase.instance.purchaseStream.listen(
        (List<PurchaseDetails> purchases) {
          _handlePurchaseUpdate(purchases);
        },
        onError: (dynamic error) {
          print('Purchase error: $error');
        },
      );

      await InAppPurchase.instance.buyConsumable(
        purchaseParams: purchaseParams,
        onOrderUpdated: (String orderId) {
          print('Order ID: $orderId');
        },
      );

      subscription.cancel();
      return true;
    } catch (e) {
      print('Purchase failed: $e');
      return false;
    }
  }

  static Future<ProductDetails> _getProductDetails(String productId) async {
    final List<ProductDetails> products =
        await InAppPurchase.instance.queryProductDetails({productId});
    if (products.isNotEmpty) {
      return products.first;
    }
    throw Exception('Product not found');
  }

  static Future<void> _handlePurchaseUpdate(
      List<PurchaseDetails> purchases) async {
    for (final PurchaseDetails purchase in purchases) {
      if (purchase.status == PurchaseStatus.purchased ||
          purchase.status == PurchaseStatus.restored) {
        await _verifyAndProcessPurchase(purchase);
      }
    }
  }

  static Future<void> _verifyAndProcessPurchase(PurchaseDetails purchase) async {
    try {
      final Map<String, dynamic> payload = {
        'transaction_id': purchase.identifier,
        'product_id': purchase.productID,
        'amount': purchase.paymentData.price,
        'currency': purchase.paymentData.currencyCode,
        'merchant_id': _merchantId,
        'timestamp': DateTime.now().toIso8601String(),
      };

      final response = await http.post(
        Uri.parse('$_apiUrl/verify'),
        headers: {
          'Content-Type': 'application/json',
          'Authorization': 'Bearer $_apiKey',
        },
        body: jsonEncode(payload),
      );

      if (response.statusCode == 200) {
        await InAppPurchase.instance.completePurchase(purchase);
        print('Purchase verified and completed');
      } else {
        print('Verification failed: ${response.body}');
      }
    } catch (e) {
      print('Processing error: $e');
    }
  }

  static Future<bool> processWalletPayment(
      double amount, String currency, String walletType) async {
    try {
      final wallet = MobileWallet(
        walletType: walletType,
        amount: amount,
        currency: currency,
      );

      final result = await wallet.processPayment();
      return result.success;
    } catch (e) {
      print('Wallet payment failed: $e');
      return false;
    }
  }

  static Future<String> createSecureToken() async {
    try {
      final response = await http.post(
        Uri.parse('$_apiUrl/token'),
        headers: {
          'Content-Type': 'application/json',
          'Authorization': 'Bearer $_apiKey',
        },
        body: jsonEncode({
          'merchant_id': _merchantId,
          'timestamp': DateTime.now().toIso8601String(),
        }),
      );

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        return data['token'];
      }
      return '';
    } catch (e) {
      print('Token creation failed: $e');
      return '';
    }
  }

  static Future<bool> validatePCICompliance() async {
    try {
      final response = await http.get(
        Uri.parse('$_apiUrl/compliance'),
        headers: {
          'Authorization': 'Bearer $_apiKey',
        },
      );

      return response.statusCode == 200;
    } catch (e) {
      print('PCI compliance check failed: $e');
      return false;
    }
  }
}

