        minimumSize: const Size(120, 50),
        backgroundColor: Colors.blue,
      ),
      child: Text(label),
    );
  }
}

class SecurePaymentService {
  static Future<bool> initializePayment() async {
    try {
      final bool isAvailable = await InAppPurchase.instance.isAvailable();
      final bool pciCompliant = await PaymentProcessor.validatePCICompliance();
      
      return isAvailable && pciCompliant;
    } catch (e) {
      print('Payment initialization failed: $e');
      return false;
    }
  }

  static Future<String> getSecureToken() async {
    return await PaymentProcessor.createSecureToken();
  }
}

class PaymentManager {
  static Future<void> handlePayment(
      double amount, String currency, String type) async {
    try {
      switch (type) {
        case 'in_app':
          await PaymentProcessor.purchaseProduct('premium_subscription');
          break;
        case 'wallet':
          await PaymentProcessor.processWalletPayment(amount, currency, 'apple_pay');
          break;
        default:
          throw Exception('Unsupported payment type');
      }
    } catch (e) {
      print('Payment failed: $e');
      rethrow;
    }
  }
}